class Solution:
    def shiftingLetters(self, s, shifts):
        n = len(s)
        net = [0] * n
        for a, b, d in shifts:
            step = 1 if d == 1 else -1
            for i in range(a, b + 1):
                net[i] += step
        res = []
        for i, ch in enumerate(s):
            v = (ord(ch) - 97 + net[i]) % 26
            res.append(chr(97 + v))
        return ''.join(res)

