class Solution:
    def shiftingLetters(self, s, shifts):
        n = len(s)
        diff = [0] * (n + 1)
        for a, b, d in shifts:
            step = 1 if d == 1 else -1
            diff[a] += step
            diff[b + 1] -= step
        res = []
        cur = 0
        for i, ch in enumerate(s):
            cur += diff[i]
            v = (ord(ch) - 97 + cur) % 26
            res.append(chr(97 + v))
        return ''.join(res)

