var shiftingLetters = function(s, shifts) {
    const n = s.length;
    const diff = new Array(n + 1).fill(0);
    for (const [a, b, d] of shifts) {
        const step = d === 1 ? 1 : -1;
        diff[a] += step;
        diff[b + 1] -= step;
    }
    const res = [];
    let cur = 0;
    for (let i = 0; i < n; i++) {
        cur += diff[i];
        let v = (s.charCodeAt(i) - 97 + cur) % 26;
        if (v < 0) v += 26;
        res.push(String.fromCharCode(97 + v));
    }
    return res.join('');
};
